// Parity tests — load vectors.json (generated by reference/cmd/genvectors) and
// verify the Rust port produces byte-identical output for every case.
//
// To regenerate the vectors locally:
//   cd reference && go run ./cmd/genvectors ../tests/vectors.json

use serde_json::Value;

use kms_rs::crypto::aes::expand_key;
use kms_rs::crypto::kms_aes::{
    aes_decrypt_block_v4, aes_decrypt_block_v6, aes_encrypt_block_v4, aes_encrypt_block_v6,
    kms_decrypt_cbc, kms_encrypt_cbc, pkcs7_pad, pkcs7_unpad,
};
use kms_rs::crypto::v4_hash::v4_hash;
use kms_rs::crypto::v6_mac::{v6_hmac, v6_mac_key};
use kms_rs::kms::base::{
    server_logic, GenericRequestHeader, KmsRequest, KmsResponse, ServerConfig,
};
use kms_rs::kms::filetime::{filetime_to_unix, unix_to_filetime};
use kms_rs::kms::utf16::{decode_utf16le, encode_utf16le};
use kms_rs::kms::uuid::KmsUuid;
use kms_rs::kms::versions::handle_v4_request;
use kms_rs::rpc::{
    build_bind_ack_response, build_bind_request, build_msrpc_response, build_rpc_request,
    MsRpcRequestHeader,
};

const VECTORS_JSON_PATH: &str = "tests/vectors.json";

fn vectors() -> Value {
    let data = std::fs::read_to_string(VECTORS_JSON_PATH).unwrap_or_else(|e| {
        panic!(
            "failed to read {}: {} — generate it with `cd reference && go run ./cmd/genvectors ../tests/vectors.json`",
            VECTORS_JSON_PATH, e
        )
    });
    serde_json::from_str(&data).expect("invalid vectors.json")
}

fn hex_str(b: &[u8]) -> String {
    let mut s = String::with_capacity(b.len() * 2);
    for &x in b {
        s.push_str(&format!("{:02x}", x));
    }
    s
}

fn from_hex(s: &str) -> Vec<u8> {
    let bytes = s.as_bytes();
    assert!(bytes.len() % 2 == 0, "odd-length hex: {}", s);
    let mut out = Vec::with_capacity(bytes.len() / 2);
    let mut i = 0;
    while i < bytes.len() {
        let hi = hex_val(bytes[i]).expect("bad hex");
        let lo = hex_val(bytes[i + 1]).expect("bad hex");
        out.push((hi << 4) | lo);
        i += 2;
    }
    out
}

fn hex_val(c: u8) -> Option<u8> {
    match c {
        b'0'..=b'9' => Some(c - b'0'),
        b'a'..=b'f' => Some(c - b'a' + 10),
        b'A'..=b'F' => Some(c - b'A' + 10),
        _ => None,
    }
}

// ---------- helpers for case iteration ----------

fn arr<'a>(v: &'a Value, key: &str) -> &'a Vec<Value> {
    v.get(key)
        .unwrap_or_else(|| panic!("missing {}", key))
        .as_array()
        .unwrap_or_else(|| panic!("{} not an array", key))
}

fn s<'a>(v: &'a Value, k: &str) -> &'a str {
    v.get(k)
        .unwrap_or_else(|| panic!("missing field {}", k))
        .as_str()
        .unwrap_or_else(|| panic!("field {} not a string", k))
}

fn opt_s<'a>(v: &'a Value, k: &str) -> Option<&'a str> {
    v.get(k).and_then(|x| x.as_str())
}

fn b(v: &Value, k: &str) -> bool {
    v.get(k).and_then(|x| x.as_bool()).unwrap_or(false)
}

fn u(v: &Value, k: &str) -> u64 {
    v.get(k).and_then(|x| x.as_u64()).unwrap_or(0)
}

// ---------- Tests ----------

#[test]
fn parity_pkcs7_pad() {
    for case in arr(&vectors(), "pkcs7_pad") {
        let input = from_hex(s(case, "input"));
        let out = pkcs7_pad(&input, 16);
        assert_eq!(hex_str(&out), s(case, "out"));
    }
}

#[test]
fn parity_pkcs7_unpad() {
    for case in arr(&vectors(), "pkcs7_unpad") {
        let input = from_hex(s(case, "input"));
        let res = pkcs7_unpad(&input);
        if b(case, "ok") {
            let out = res.expect("expected ok");
            assert_eq!(hex_str(&out), s(case, "out"));
        } else {
            assert!(res.is_err(), "expected error for {}", s(case, "input"));
        }
    }
}

#[test]
fn parity_v4_block() {
    for case in arr(&vectors(), "v4_block") {
        let input = from_hex(s(case, "input"));
        let mut enc = [0u8; 16];
        aes_encrypt_block_v4(&input, &mut enc);
        assert_eq!(hex_str(&enc), s(case, "enc"));
        let mut dec = [0u8; 16];
        aes_decrypt_block_v4(&enc, &mut dec);
        assert_eq!(hex_str(&dec), s(case, "dec_of_enc"));
    }
}

#[test]
fn parity_v6_block() {
    for case in arr(&vectors(), "v6_block") {
        let input = from_hex(s(case, "input"));
        let mut enc = [0u8; 16];
        aes_encrypt_block_v6(&input, &mut enc);
        assert_eq!(hex_str(&enc), s(case, "enc"));
        let mut dec = [0u8; 16];
        aes_decrypt_block_v6(&enc, &mut dec);
        assert_eq!(hex_str(&dec), s(case, "dec_of_enc"));
    }
}

#[test]
fn parity_v5_cbc() {
    for case in arr(&vectors(), "v5_cbc") {
        let iv = from_hex(s(case, "iv"));
        let plain = from_hex(s(case, "plain"));
        let cipher = kms_encrypt_cbc(&plain, &iv, false).unwrap();
        assert_eq!(hex_str(&cipher), s(case, "cipher"));
        let dec = kms_decrypt_cbc(&cipher, &iv, false).unwrap();
        assert_eq!(hex_str(&dec), s(case, "decrypted"));
    }
}

#[test]
fn parity_v6_cbc() {
    for case in arr(&vectors(), "v6_cbc") {
        let iv = from_hex(s(case, "iv"));
        let plain = from_hex(s(case, "plain"));
        let cipher = kms_encrypt_cbc(&plain, &iv, true).unwrap();
        assert_eq!(hex_str(&cipher), s(case, "cipher"));
        let dec = kms_decrypt_cbc(&cipher, &iv, true).unwrap();
        assert_eq!(hex_str(&dec), s(case, "decrypted"));
    }
}

