#[test]
fn parity_filetime() {
    for case in arr(&vectors(), "filetime") {
        let ft: i64 = s(case, "filetime").parse().unwrap();
        let want_secs: i64 = s(case, "secs").parse().unwrap();
        let want_nanos: u64 = u(case, "nanos");
        let (secs, nanos) = filetime_to_unix(ft);
        assert_eq!(secs, want_secs, "secs mismatch for ft {}", ft);
        assert_eq!(nanos as u64, want_nanos, "nanos mismatch for ft {}", ft);
        let roundtrip: i64 = s(case, "roundtrip").parse().unwrap();
        assert_eq!(unix_to_filetime(secs, nanos), roundtrip);
    }
}

#[test]
fn parity_utf16le() {
    for case in arr(&vectors(), "utf16le") {
        let input = s(case, "input");
        let enc = encode_utf16le(input);
        assert_eq!(hex_str(&enc), s(case, "utf16le"));
        // Append two null bytes (mirrors Go's test) and decode.
        let mut padded = from_hex(s(case, "utf16le"));
        padded.push(0);
        padded.push(0);
        let decoded = decode_utf16le(&padded);
        assert_eq!(decoded, s(case, "decoded"));
    }
}

