#[test]
fn parity_server_logic() {
    let vectors = vectors();
    let cases = arr(&vectors, "server_logic");
    // First case: full request + response wire.
    let first = &cases[0];
    let req = KmsRequest::parse(&from_hex(s(first, "request"))).unwrap();
    let mut cfg = ServerConfig::default();
    cfg.epid = "03612-00206-471-111111-03-1033-19041.0000-1232024".into();
    cfg.activation = 120;
    cfg.renewal = 10080;
    let resp = server_logic(&req, &cfg);
    assert_eq!(hex_str(&resp.marshal()), s(first, "response_wire"));
    assert_eq!(hex_str(&resp.kms_epid), s(first, "epid_utf16le"));
    assert_eq!(resp.current_client_count as u64, u(first, "current_client_count"));

    // Subsequent cases: client_count -> expected current_client_count.
    for case in &cases[1..] {
        let cc = u(case, "client_count") as u32;
        let expected = u(case, "current_client_count") as u32;
        let mut cfg2 = ServerConfig::default();
        cfg2.epid = "fixed-epid".into();
        cfg2.client_count = if cc > 0 { Some(cc) } else { Some(0) };
        // Match Go behaviour: cc == 0 yields 0 (since none of the conditions hit).
        let resp = server_logic(&req, &cfg2);
        assert_eq!(resp.current_client_count, expected, "client_count={}", cc);
    }
}

#[test]
fn parity_v5_envelope() {
    parity_v5_v6_envelope("v5_envelope", false);
}

#[test]
fn parity_v6_envelope() {
    parity_v5_v6_envelope("v6_envelope", true);
}

fn parity_v5_v6_envelope(key: &str, is_v6: bool) {
    use kms_rs::crypto::v6_mac::v6_hmac_parts;
    use kms_rs::kms::base::get_padding;
    use sha2::{Digest, Sha256};

    for case in arr(&vectors(), key) {
        let req_bytes = from_hex(s(case, "request_bytes"));
        let salt = from_hex(s(case, "salt"));
        let decrypted_salt = from_hex(s(case, "decrypted_salt"));
        let random_salt = from_hex(s(case, "random_salt"));
        let salt_s = from_hex(s(case, "salt_s"));
        let epid_utf16le = from_hex(s(case, "epid_utf16le"));
        let hwid = from_hex(s(case, "hwid"));
        let want_response_bytes = from_hex(s(case, "response_bytes"));
        let want_encrypted = from_hex(s(case, "encrypted"));
        let want_full = from_hex(s(case, "full"));

        let req = KmsRequest::parse(&req_bytes).unwrap();
        let mut cfg = ServerConfig::default();
        cfg.hwid = hwid.clone();
        cfg.set_epid_bytes(epid_utf16le.clone());
        let resp = server_logic(&req, &cfg);
        let response_bytes = resp.marshal();
        assert_eq!(response_bytes, want_response_bytes, "response_bytes mismatch");

        let hash_result = Sha256::digest(&random_salt);

        let (encrypted, iv): (Vec<u8>, Vec<u8>) = if is_v6 {
            let mut msg = Vec::with_capacity(response_bytes.len() + 16 + 32 + cfg.hwid.len() + 16 + 16);
            msg.extend_from_slice(&response_bytes);
            for i in 0..16 {
                msg.push(salt[i] ^ decrypted_salt[i] ^ random_salt[i]);
            }
            msg.extend_from_slice(&hash_result);
            msg.extend_from_slice(&cfg.hwid);
            for i in 0..16 {
                msg.push(salt[i] ^ decrypted_salt[i]);
            }
            let dsalt_s = kms_decrypt_cbc(&salt_s, &salt_s, true).unwrap();
            let hmac_key = v6_mac_key(req.request_time);
            let mut xor_salts = [0u8; 16];
            for i in 0..16 {
                xor_salts[i] = salt_s[i] ^ dsalt_s[i];
            }
            let digest = v6_hmac_parts(&hmac_key, &[&xor_salts, &msg]);
            msg.extend_from_slice(&digest[16..]);
            let padded = pkcs7_pad(&msg, 16);
            let enc = kms_encrypt_cbc(&padded, &salt_s, true).unwrap();
            (enc, salt_s.clone())
        } else {
            let mut rd = Vec::with_capacity(response_bytes.len() + 16 + 32);
            rd.extend_from_slice(&response_bytes);
            for i in 0..16 {
                rd.push(decrypted_salt[i] ^ salt[i] ^ random_salt[i]);
            }
            rd.extend_from_slice(&hash_result);
            let padded = pkcs7_pad(&rd, 16);
            let enc = kms_encrypt_cbc(&padded, &salt, false).unwrap();
            (enc, salt.clone())
        };

        assert_eq!(encrypted, want_encrypted, "encrypted mismatch");

        let body_length = (2 + 2 + iv.len() + encrypted.len()) as u32;
        let padding = vec![0u8; get_padding(body_length as usize)];
        let mut full = Vec::with_capacity(4 + 4 + 4 + 2 + 2 + iv.len() + encrypted.len() + padding.len());
        full.extend_from_slice(&body_length.to_le_bytes());
        full.extend_from_slice(&0x00000200u32.to_be_bytes());
        full.extend_from_slice(&body_length.to_le_bytes());
        full.extend_from_slice(&req.version_minor.to_le_bytes());
        full.extend_from_slice(&req.version_major.to_le_bytes());
        full.extend_from_slice(&iv);
        full.extend_from_slice(&encrypted);
        full.extend_from_slice(&padding);
        assert_eq!(full, want_full, "full wire mismatch");
    }
}

#[test]
fn parity_constants() {
    let v = vectors();
    let c = &v["constants"];
    assert_eq!(u(c, "msrpc_header_size"), kms_rs::rpc::MSRPC_HEADER_SIZE as u64);
    assert_eq!(
        u(c, "msrpc_request_header_size"),
        kms_rs::rpc::MSRPC_REQUEST_HEADER_SIZE as u64
    );
    assert_eq!(
        u(c, "msrpc_resp_header_size"),
        kms_rs::rpc::MSRPC_RESP_HEADER_SIZE as u64
    );
    assert_eq!(u(c, "ctx_item_size"), kms_rs::rpc::CTX_ITEM_SIZE as u64);
    assert_eq!(
        u(c, "ctx_item_result_size"),
        kms_rs::rpc::CTX_ITEM_RESULT_SIZE as u64
    );
}

// Keep a reference to `expand_key` to suppress unused-import warnings.
#[test]
fn ensure_expand_key_linked() {
    let k = expand_key(&[0u8; 16], 16, 176);
    assert_eq!(k.len(), 176);
}
